37: /**
38:  * Scram message salt and hash functions defined in <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>.
39:  */
40: public class ScramFormatter {
41: 
42:     private static final Pattern EQUAL = Pattern.compile("=", Pattern.LITERAL);
43:     private static final Pattern COMMA = Pattern.compile(",", Pattern.LITERAL);
44:     private static final Pattern EQUAL_TWO_C = Pattern.compile("=2C", Pattern.LITERAL);
45:     private static final Pattern EQUAL_THREE_D = Pattern.compile("=3D", Pattern.LITERAL);
46: 
47:     private final MessageDigest messageDigest;
48:     private final Mac mac;
49:     private final SecureRandom random;
50: 
51:     public ScramFormatter(ScramMechanism mechanism) throws NoSuchAlgorithmException {
52:         this.messageDigest = MessageDigest.getInstance(mechanism.hashAlgorithm());
53:         this.mac = Mac.getInstance(mechanism.macAlgorithm());
54:         this.random = new SecureRandom();
55:     }
56: 
57:     public byte[] hmac(byte[] key, byte[] bytes) throws InvalidKeyException {
58:         mac.init(new SecretKeySpec(key, mac.getAlgorithm()));
59:         return mac.doFinal(bytes);
60:     }
61: 
62:     public byte[] hash(byte[] str) {
63:         return messageDigest.digest(str);
64:     }
65: 
66:     public static byte[] xor(byte[] first, byte[] second) {
67:         if (first.length != second.length)
68:             throw new IllegalArgumentException("Argument arrays must be of the same length");
69:         byte[] result = new byte[first.length];
70:         for (int i = 0; i < result.length; i++)
71:             result[i] = (byte) (first[i] ^ second[i]);
72:         return result;
73:     }
74: 
75:     public byte[] hi(byte[] str, byte[] salt, int iterations) throws InvalidKeyException {
76:         mac.init(new SecretKeySpec(str, mac.getAlgorithm()));
77:         mac.update(salt);
78:         byte[] u1 = mac.doFinal(new byte[]{0, 0, 0, 1});
79:         byte[] prev = u1;
80:         byte[] result = u1;
81:         for (int i = 2; i <= iterations; i++) {
82:             byte[] ui = hmac(str, prev);
83:             result = xor(result, ui);
84:             prev = ui;
85:         }
86:         return result;
87:     }
88: 
89:     public static byte[] normalize(String str) {
90:         return toBytes(str);
91:     }
92: 
93:     public byte[] saltedPassword(String password, byte[] salt, int iterations) throws InvalidKeyException {
94:         return hi(normalize(password), salt, iterations);
95:     }
96: 
97:     public byte[] clientKey(byte[] saltedPassword) throws InvalidKeyException {
98:         return hmac(saltedPassword, toBytes("Client Key"));
99:     }
100: 
101:     public byte[] storedKey(byte[] clientKey) {
102:         return hash(clientKey);
103:     }
104: 
105:     public static String saslName(String username) {
106:         String replace1 = EQUAL.matcher(username).replaceAll(Matcher.quoteReplacement("=3D"));
107:         return COMMA.matcher(replace1).replaceAll(Matcher.quoteReplacement("=2C"));
108:     }
109: 
110:     public static String username(String saslName) {
111:         String username = EQUAL_TWO_C.matcher(saslName).replaceAll(Matcher.quoteReplacement(","));
112:         if (EQUAL_THREE_D.matcher(username).replaceAll(Matcher.quoteReplacement("")).indexOf('=') >= 0) {
113:             throw new IllegalArgumentException("Invalid username: " + saslName);
114:         }
115:         return EQUAL_THREE_D.matcher(username).replaceAll(Matcher.quoteReplacement("="));
116:     }
