118:     public static String authMessage(String clientFirstMessageBare, String serverFirstMessage, String clientFinalMessageWithoutProof) {
119:         return clientFirstMessageBare + "," + serverFirstMessage + "," + clientFinalMessageWithoutProof;
120:     }
