128:         byte[] clientKey = clientKey(saltedPassword);
129:         byte[] storedKey = hash(clientKey);
130:         byte[] clientSignature = hmac(storedKey, authMessage(clientFirstMessage, serverFirstMessage, clientFinalMessage));
131:         return xor(clientKey, clientSignature);
132:     }
