135:         return toBytes(authMessage(clientFirstMessage.clientFirstMessageBare(),
136:                 serverFirstMessage.toMessage(),
137:                 clientFinalMessage.clientFinalMessageWithoutProof()));
138:     }
139: 
140:     public byte[] storedKey(byte[] clientSignature, byte[] clientProof) {
141:         return hash(xor(clientSignature, clientProof));
142:     }
143: 
144:     public byte[] serverKey(byte[] saltedPassword) throws InvalidKeyException {
145:         return hmac(saltedPassword, toBytes("Server Key"));
146:     }
