173:     public ScramCredential generateCredential(String password, int iterations) {
174:         try {
175:             byte[] salt = secureRandomBytes();
176:             byte[] saltedPassword = saltedPassword(password, salt, iterations);
177:             return generateCredential(salt, saltedPassword, iterations);
178:         } catch (InvalidKeyException e) {
179:             throw new KafkaException("Could not create credential", e);
180:         }
