184:         try {
185:             byte[] clientKey = clientKey(saltedPassword);
186:             byte[] storedKey = storedKey(clientKey);
187:             byte[] serverKey = serverKey(saltedPassword);
188:             return new ScramCredential(salt, storedKey, serverKey, iterations);
189:         } catch (InvalidKeyException e) {
190:             throw new KafkaException("Could not create credential", e);
191:         }
192:     }
